    monkeypatch.setattr(customer_read_service,'list_customer_status',lambda *a,**k:_rows(_staged()))
    p=_w(tmp_path,_gate(),'p2.json'); s=_snap(tmp_path,_live())
    r=CliRunner().invoke(app,['production','single-customer-firewall-apply-gate','--firewall-plan-gate-json',str(p),'--operator','vahid','--reason','ok','--operator-confirmed','--i-understand-apply-gate-only','--i-understand-no-firewall-apply-in-this-pr','--i-understand-no-nat-apply-in-this-pr','--i-understand-no-iptables-restore-in-this-pr','--i-understand-no-production-traffic','--i-understand-no-miner-traffic-yet','--i-confirm-limited-single-customer-scope','--i-confirm-restore-point-required-before-apply','--i-confirm-operator-lock-required-before-apply','--i-confirm-rollback-artifact-required-before-apply','--i-confirm-pre-apply-snapshot-required-before-apply','--i-confirm-post-apply-verification-required','--i-confirm-runtime-path-evidence-required-after-apply','--i-confirm-abuse-1h-evidence-required-before-customer-traffic','--i-confirm-restart-container-order-evidence-required-before-customer-traffic','--live-snapshot-file',str(s),'--output','human','--config','configs/mpf.example.yaml']); assert r.exit_code==0
